:root {
  /* Blueprint colors */
  --color-background: #FAFAF8;
  --color-wall-fill: #2D3748;
  --color-wall-stroke: #1A202C;
  --color-grid-minor: #E4E7EC;
  --color-grid-major: #CDD5DF;
  --color-selection: #0D7C66;
  --color-selection-fill: rgba(13, 124, 102, 0.08);

  /* UI colors */
  --color-text-primary: #1A1D23;
  --color-text-secondary: #6B7080;
  --color-text-tertiary: #9CA3AF;
  --color-panel-bg: #F3F3F0;
  --color-panel-bg-alt: #FAFAF8;
  --color-surface-elevated: #FFFFFF;
  --color-border: #DDDDD8;
  --color-border-subtle: rgba(0, 0, 0, 0.06);
  --color-accent: #0D7C66;
  --color-accent-hover: #0A6352;
  --color-accent-subtle: rgba(13, 124, 102, 0.08);
  --color-danger: #DC2626;
  --color-danger-hover: #B91C1C;
  --color-danger-subtle: rgba(220, 38, 38, 0.06);

  /* Layout */
  --toolbar-height: 48px;
  --sidebar-width: 240px;
  --properties-width: 280px;

  /* Typography */
  --font-ui: 'DM Sans', system-ui, -apple-system, sans-serif;
  --font-blueprint: 'JetBrains Mono', 'Courier New', monospace;

  /* Spacing */
  --space-xs: 4px;
  --space-sm: 8px;
  --space-md: 12px;
  --space-lg: 16px;
  --space-xl: 24px;

  /* Borders */
  --radius-sm: 5px;
  --radius-md: 8px;
  --radius-lg: 12px;

  /* Shadows */
  --shadow-sm: 0 1px 2px rgba(0, 0, 0, 0.05);
  --shadow-md: 0 2px 8px rgba(0, 0, 0, 0.08);
  --shadow-lg: 0 4px 16px rgba(0, 0, 0, 0.12);
  --shadow-overlay: 0 8px 32px rgba(0, 0, 0, 0.16), 0 0 0 1px rgba(0, 0, 0, 0.04);

  /* Transitions */
  --ease-out: cubic-bezier(0.16, 1, 0.3, 1);
  --duration-fast: 0.1s;
  --duration-normal: 0.2s;
}

