 75→export default function Toolbar({
 76→  onNew,
 77→  onSave,
 78→  onLoad,
 79→  isSidebarCollapsed,
 80→  isPropertiesCollapsed,
 81→  onToggleSidebar,
 82→  onToggleProperties,
 83→}) {
 84→  const { activeTool, showGrid, snapEnabled, activeFloorId, viewMode, workspaceMode, dispatch: editorDispatch } = useEditor();
 85→  const { project, isDirty, canUndo, canRedo, dispatch } = useProject();
 86→  const {
 87→    canCopySelection,
 88→    canPaste,
 89→    copySelection,
 90→    cutSelection,
 91→    beginPaste,
 92→  } = usePlanClipboardController();
 93→  const isPlanView = workspaceMode === 'model' && viewMode === 'plan';
 94→
 95→  const [toolMenuOpen, setToolMenuOpen] = useState(false);
 96→  const toolMenuRef = useRef(null);
