234→          title="Plan View"
235→        >
236→          Plan
237→        </button>
238→        <button
239→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_front' ? styles.active : ''}`}
240→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_front' })}
241→          title="Front Elevation"
242→        >
243→          Front
244→        </button>
245→        <button
246→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_rear' ? styles.active : ''}`}
247→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_rear' })}
248→          title="Rear Elevation"
249→        >
250→          Rear
251→        </button>
252→        <button
253→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_left' ? styles.active : ''}`}
254→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_left' })}
255→          title="Left Elevation"
256→        >
257→          Left
258→        </button>
259→        <button
260→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'elevation_right' ? styles.active : ''}`}
261→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'elevation_right' })}
262→          title="Right Elevation"
263→        >
264→          Right
265→        </button>
266→        <button
267→          className={`${styles.btn} ${workspaceMode === 'model' && viewMode === 'section_view' ? styles.active : ''}`}
268→          onClick={() => editorDispatch({ type: 'SET_VIEW_MODE', viewMode: 'section_view' })}
269→          title="Section View"
270→        >
271→          Section
272→        </button>
273→        <button
274→          className={`${styles.btn} ${workspaceMode === 'sheet' ? styles.active : ''}`}
275→          onClick={() => editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'sheet' })}
276→          title="Sheet Workspace"
277→        >
278→          Sheets
279→        </button>
280→      </div>
281→
282→      <div className={styles.dropdown} ref={toolMenuRef}>
283→        <button
284→          className={`${styles.btn} ${styles.dropdownTrigger}`}
285→          onClick={() => setToolMenuOpen(!toolMenuOpen)}
