284→                style={{
285→                  alignSelf: 'flex-start',
286→                  padding: '8px 14px',
287→                  border: '1px solid var(--color-border)',
288→                  borderRadius: 'var(--radius-sm)',
289→                  cursor: 'pointer',
290→                  fontSize: '12px',
291→                  fontWeight: 600,
292→                  background: 'var(--color-surface-elevated)',
293→                }}
294→              >
295→                Open Project File
