  1→import { lazy, Suspense, useState, useEffect, useCallback, useMemo, useRef } from 'react';
  2→import { ProjectProvider, useProject } from './ProjectProvider';
  3→import { EditorProvider, useEditor } from './EditorProvider';
  4→import { ClipboardProvider } from './ClipboardProvider';
  5→import SvgCanvas from '@/renderers/SvgCanvas';
  6→import SheetCanvas from '@/renderers/SheetCanvas';
  7→import Toolbar from '@/ui/Toolbar';
  8→import Sidebar from '@/ui/Sidebar';
  9→import PropertiesPanel from '@/ui/PropertiesPanel';
 10→import Modal from '@/ui/Modal';
 11→import { createProject } from '@/domain/models';
 12→import { getDefaultActiveFloorId, getOrderedFloors } from '@/domain/floorModels';
 13→import { saveProject, loadProject, listProjects, deleteProject } from '@/persistence/storage';
 14→import {
 15→  exportProjectFile,
 16→  importProjectFile,
 17→  isFilePickerAbortError,
 18→  openProjectFile,
 19→} from '@/persistence/fileTransfer';
 20→import { useAutosave } from '@/persistence/useAutosave';
 21→import { isTypingTarget } from '@/utils/keyboard';
 22→import styles from './App.module.css';
 23→import modalStyles from '@/ui/Modal.module.css';
 24→
 25→const ThreePreviewPanel = lazy(() => import('@/three/viewer/ThreePreviewPanel'));
 26→
 27→function EditorShell({
 28→  project,
 29→  handleNew,
 30→  handleSave,
 31→  handleLoadClick,
 32→  isSidebarCollapsed,
 33→  isPropertiesCollapsed,
 34→  onToggleSidebar,
 35→  onToggleProperties,
 36→}) {
 37→  const {
 38→    workspaceMode,
 39→    activeSheetId,
 40→    activeFloorId,
 41→    dispatch: editorDispatch,
 42→  } = useEditor();
 43→
 44→  useEffect(() => {
 45→    const sheets = project.sheets || [];
 46→    if (!sheets.length) {
 47→      if (activeSheetId !== null) {
 48→        editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: null });
 49→      }
 50→      if (workspaceMode === 'sheet') {
 51→        editorDispatch({ type: 'SET_WORKSPACE_MODE', workspaceMode: 'model' });
 52→      }
 53→      return;
 54→    }
 55→
 56→    if (!activeSheetId || !sheets.some((sheet) => sheet.id === activeSheetId)) {
 57→      editorDispatch({ type: 'SET_ACTIVE_SHEET', sheetId: sheets[0].id });
 58→    }
 59→  }, [activeSheetId, editorDispatch, project.sheets, workspaceMode]);
 60→
 61→  return (
 62→    <div
 63→      className={styles.layout}
 64→      style={{
 65→        '--layout-sidebar-width': isSidebarCollapsed ? '0px' : 'var(--sidebar-width)',
 66→        '--layout-properties-width': isPropertiesCollapsed ? '0px' : 'var(--properties-width)',
 67→      }}
 68→    >
 69→      <div className={styles.toolbar}>
 70→        <Toolbar
 71→          onNew={handleNew}
 72→          onSave={handleSave}
 73→          onLoad={handleLoadClick}
 74→          isSidebarCollapsed={isSidebarCollapsed}
 75→          isPropertiesCollapsed={isPropertiesCollapsed}
 76→          onToggleSidebar={onToggleSidebar}
 77→          onToggleProperties={onToggleProperties}
 78→        />
 79→      </div>
 80→      <div className={`${styles.sidebar} ${isSidebarCollapsed ? styles.panelHidden : ''}`}>
 81→        <Sidebar />
 82→      </div>
 83→      <div className={styles.canvas}>
 84→        {workspaceMode === 'sheet' ? (
 85→          <SheetCanvas />
 86→        ) : (
 87→          <div className={styles.modelWorkspace}>
 88→            <div className={styles.primaryCanvas}>
 89→              <SvgCanvas />
 90→            </div>
 91→            <div className={styles.preview}>
 92→              <Suspense fallback={<div className={styles.previewFallback}>Loading 3D preview...</div>}>
 93→                <ThreePreviewPanel
 94→                  project={project}
 95→                  activeFloorId={activeFloorId}
 96→                />
 97→              </Suspense>
 98→            </div>
 99→          </div>
100→        )}
101→      </div>
102→      <div className={`${styles.properties} ${isPropertiesCollapsed ? styles.panelHidden : ''}`}>
103→        <PropertiesPanel />
104→      </div>
105→    </div>
106→  );
