109→function AppInner() {
110→  const { project, isDirty, dispatch } = useProject();
111→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
112→  const availableFloorIds = useMemo(() => orderedFloors.map((floor) => floor.id), [orderedFloors]);
113→  const initialActiveFloorId = getDefaultActiveFloorId(project);
114→  const [showLoadModal, setShowLoadModal] = useState(false);
115→  const [savedProjects, setSavedProjects] = useState([]);
116→  const [isSidebarCollapsed, setIsSidebarCollapsed] = useState(false);
117→  const [isPropertiesCollapsed, setIsPropertiesCollapsed] = useState(false);
118→  const [projectFileHandle, setProjectFileHandle] = useState(null);
119→  const importInputRef = useRef(null);
120→
121→  useAutosave(project, isDirty, dispatch);
122→
123→  // beforeunload warning
124→  useEffect(() => {
125→    const handler = (e) => {
126→      if (isDirty) {
127→        e.preventDefault();
128→        e.returnValue = '';
129→      }
130→    };
131→    window.addEventListener('beforeunload', handler);
132→    return () => window.removeEventListener('beforeunload', handler);
133→  }, [isDirty]);
134→
135→  const handleNew = useCallback(() => {
136→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
137→    setProjectFileHandle(null);
138→    dispatch({ type: 'PROJECT_NEW', project: createProject() });
139→  }, [isDirty, dispatch]);
140→
141→  const handleSave = useCallback(async () => {
142→    try {
143→      const { fileHandle } = await exportProjectFile(project, { fileHandle: projectFileHandle });
144→      setProjectFileHandle(fileHandle);
145→      try {
146→        await saveProject(project);
147→      } catch {
148→        // Browser draft sync is secondary to file save.
149→      }
150→      dispatch({ type: 'MARK_SAVED' });
151→    } catch (err) {
152→      if (isFilePickerAbortError(err)) return;
153→      alert('Failed to save project file: ' + err.message);
154→    }
155→  }, [project, projectFileHandle, dispatch]);
156→
157→  // Ctrl+S save
158→  useEffect(() => {
159→    const handler = (e) => {
160→      if (isTypingTarget(e.target)) return;
161→      if ((e.ctrlKey || e.metaKey) && e.key === 's') {
162→        e.preventDefault();
163→        handleSave();
164→      }
165→    };
166→    window.addEventListener('keydown', handler);
167→    return () => window.removeEventListener('keydown', handler);
168→  }, [handleSave]);
169→
170→  const handleLoadClick = useCallback(async () => {
171→    setSavedProjects(await listProjects());
172→    setShowLoadModal(true);
173→  }, []);
174→
175→  const handleOpenProjectFile = useCallback(async () => {
176→    if (typeof window.showOpenFilePicker !== 'function') {
177→      importInputRef.current?.click();
178→      return;
179→    }
180→
181→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
182→      return;
183→    }
184→
185→    try {
186→      const { project: loaded, savedAt, fileHandle } = await openProjectFile();
187→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
188→      setProjectFileHandle(fileHandle);
189→      setShowLoadModal(false);
190→    } catch (err) {
191→      if (isFilePickerAbortError(err)) return;
192→      alert('Failed to import project file: ' + err.message);
193→    }
194→  }, [isDirty, dispatch]);
195→
196→  const handleImportFile = useCallback(async (e) => {
197→    const file = e.target.files?.[0] || null;
198→    e.target.value = '';
199→    if (!file) return;
200→
201→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) {
202→      return;
203→    }
204→
205→    try {
206→      const { project: loaded, savedAt } = await importProjectFile(file);
207→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
208→      setProjectFileHandle(null);
209→      setShowLoadModal(false);
210→    } catch (err) {
211→      alert('Failed to import project file: ' + err.message);
212→    }
213→  }, [isDirty, dispatch]);
214→
215→  const handleLoad = useCallback(async (id) => {
216→    if (isDirty && !window.confirm('Unsaved changes will be lost. Continue?')) return;
217→    try {
218→      const { project: loaded, savedAt } = await loadProject(id);
219→      dispatch({ type: 'PROJECT_LOAD', project: loaded, savedAt });
220→      setProjectFileHandle(null);
221→      setShowLoadModal(false);
222→    } catch (err) {
223→      alert('Failed to load project: ' + err.message);
224→    }
225→  }, [isDirty, dispatch]);
226→
227→  const handleDelete = useCallback(async (id, name) => {
228→    const confirmed = window.confirm(`Delete "${name}"? This cannot be undone.`);
229→    if (!confirmed) return;
230→
231→    try {
232→      await deleteProject(id);
233→      setSavedProjects(projects => projects.filter(project => project.id !== id));
234→    } catch (err) {
235→      alert('Failed to delete project: ' + err.message);
236→    }
237→  }, []);
238→
239→  return (
240→    <EditorProvider
241→      initialActiveFloorId={initialActiveFloorId}
242→      availableFloorIds={availableFloorIds}
243→    >
244→      <input
245→        ref={importInputRef}
246→        type="file"
247→        accept=".json,application/json"
248→        onChange={handleImportFile}
249→        style={{ display: 'none' }}
250→      />
251→
252→      <EditorShell
253→        project={project}
254→        handleNew={handleNew}
255→        handleSave={handleSave}
256→        handleLoadClick={handleLoadClick}
257→        isSidebarCollapsed={isSidebarCollapsed}
258→        isPropertiesCollapsed={isPropertiesCollapsed}
259→        onToggleSidebar={() => setIsSidebarCollapsed(value => !value)}
260→        onToggleProperties={() => setIsPropertiesCollapsed(value => !value)}
261→      />
262→
263→      {showLoadModal && (
264→        <Modal title="Open Project" onClose={() => setShowLoadModal(false)}>
265→          <div style={{ display: 'flex', flexDirection: 'column', gap: '16px' }}>
266→            <div className={modalStyles.modalCard}>
267→              <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
268→                <span className={modalStyles.modalCardTitle}>Project File</span>
269→                <span className={modalStyles.modalCardDesc}>
270→                  Open a JSON file previously saved to your computer.
271→                </span>
272→              </div>
273→              <button className={modalStyles.modalBtn} onClick={handleOpenProjectFile} style={{ alignSelf: 'flex-start' }}>
274→                Open Project File
275→              </button>
276→            </div>
277→
278→            <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
279→              <div style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
280→                <span className={modalStyles.modalCardTitle}>Browser Drafts</span>
281→                <span className={modalStyles.modalCardDesc} style={{ fontSize: '11px' }}>
282→                  Stored only in this browser on this machine.
283→                </span>
284→              </div>
285→              {savedProjects.length === 0 ? (
286→                <p style={{ color: 'var(--color-text-secondary)', fontSize: '13px', margin: 0 }}>
287→                  No browser drafts found.
288→                </p>
289→              ) : (
290→                <div style={{ display: 'flex', flexDirection: 'column', gap: '8px' }}>
291→                  {savedProjects.map(p => (
292→                    <div key={p.id} className={modalStyles.modalCard} style={{ flexDirection: 'row', justifyContent: 'space-between', alignItems: 'center' }}>
293→                      <div style={{ display: 'flex', flexDirection: 'column', gap: '4px' }}>
294→                        <span style={{ fontWeight: 500, fontSize: '13px' }}>{p.name}</span>
295→                        <span style={{ color: 'var(--color-text-secondary)', fontSize: '11px' }}>
296→                          {new Date(p.savedAt).toLocaleDateString()}
297→                        </span>
298→                      </div>
299→                      <div style={{ display: 'flex', gap: '8px' }}>
300→                        <button className={modalStyles.modalBtn} onClick={() => handleLoad(p.id)}>Load</button>
301→                        <button className={modalStyles.modalBtnDanger} onClick={() => handleDelete(p.id, p.name)}>Delete</button>
302→                      </div>
303→                    </div>
304→                  ))}
305→                </div>
306→              )}
307→            </div>
308→          </div>
309→          <button className={modalStyles.modalBtn} onClick={() => setShowLoadModal(false)} style={{ marginTop: '16px' }}>
310→            Cancel
311→          </button>
312→        </Modal>
313→      )}
314→    </EditorProvider>
315→  );
316→}
317→
318→export default function App() {
319→  return (
320→    <ProjectProvider>
321→      <ClipboardProvider>
322→        <AppInner />
323→      </ClipboardProvider>
324→    </ProjectProvider>
325→  );
326→}
