197→export function createInitialEditorState(activeFloorId = null) {
198→  const modelViewport = getInitialModelViewport();
199→  const sheetViewport = getInitialSheetViewport();
200→  return {
201→    activeTool: TOOLS.SELECT,
202→    selectedId: null,
203→    selectedType: null,
204→    toolState: {},
205→    workspaceMode: 'model',
206→    viewport: { ...modelViewport },
207→    modelViewport,
208→    sheetViewport,
209→    showGrid: true,
210→    snapEnabled: true,
211→    viewMode: 'plan',
212→    activeFloorId,
213→    activeSheetId: null,
214→    activeSectionCutId: null,
215→    statusMessage: null,
216→    regionSelection: null,
217→    pastePreview: { active: false, point: null },
218→  };
219→}
