221→export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [] }) {
222→  const [state, dispatch] = useReducer(
223→    editorReducer,
224→    initialActiveFloorId,
225→    createInitialEditorState
226→  );
227→
228→  useEffect(() => {
229→    if (!availableFloorIds.length) {
230→      if (state.activeFloorId !== null) {
231→        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
232→      }
233→      return;
234→    }
235→
236→    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
237→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
238→    }
239→  }, [availableFloorIds, state.activeFloorId]);
240→
241→  return (
242→    <EditorContext.Provider value={{ state, dispatch }}>
243→      {children}
244→    </EditorContext.Provider>
245→  );
246→}
